const NavbarUI=(()=>{let initialized=false;function init(){if(initialized)return;initialized=true;const menu=document.querySelector(".mobile-menu");const overlay=document.querySelector(".mobile-menu-overlay");const openBtn=document.querySelector(".menu-btn");const closeBtn=document.querySelector(".mobile-menu-close");function open(){if(menu)menu.classList.add("open");if(overlay)overlay.classList.add("open");document.body.style.overflow="hidden"}function close(){if(menu)menu.classList.remove("open");if(overlay)overlay.classList.remove("open");document.body.style.overflow=""}if(openBtn)openBtn.addEventListener("click",open);if(closeBtn)closeBtn.addEventListener("click",close);if(overlay)overlay.addEventListener("click",close);document.addEventListener("keydown",e=>{if(e.key==="Escape"&&menu&&menu.classList.contains("open"))close()});const path=window.location.pathname.split("/").pop()||"index.html";document.querySelectorAll(".navbar-links a, .mobile-menu-links a").forEach(a=>{const href=a.getAttribute("href");if(href===path||href==="index.html"&&path===""){a.classList.add("active")}});const langSelects=document.querySelectorAll(".lang-select");langSelects.forEach(sel=>{sel.addEventListener("change",function(){if(window.switchLang)window.switchLang(this.value)})})}return{init:init}})();window.NavbarUI=NavbarUI;